1	/**
2	 * Google Ads Script: PMAX検索語句レポート自動エクスポート
3	 *
4	 * 設置方法:
5	 *   1. Google広告管理画面 → ツールと設定 → 一括操作 → スクリプト
6	 *   2. 「+新しいスクリプト」をクリック
7	 *   3. このスクリプトの内容を貼り付け
8	 *   4. SPREADSHEET_ID を確認（既に設定済み）
9	 *   5. 「承認」→「実行」でテスト
10	 *   6. 「スケジュール」→「毎日」に設定（推奨: 午前6時）
11	 *
12	 * 出力先: https://docs.google.com/spreadsheets/d/1Qw41z2YXJSbTRSj0ohIFBHw9SQdrFmIzi24KyTVSuxU
13	 * シート名: 検索語句レポート
14	 *
15	 * エクスポート内容:
16	 *   - 検索語句
17	 *   - キャンペーン名
18	 *   - 表示回数
19	 *   - クリック数
20	 *   - 費用
21	 *   - コンバージョン
22	 *   - コンバージョン値
23	 *   - CTR
24	 *   - CVR
25	 *   - CPC
26	 *   - CPA
27	 */
28	
29	var SPREADSHEET_ID = '1Qw41z2YXJSbTRSj0ohIFBHw9SQdrFmIzi24KyTVSuxU';
30	var SHEET_NAME = '検索語句レポート';
31	
32	// デフォルト: 過去30日間
33	var DATE_RANGE = 'LAST_30_DAYS';
34	
35	function main() {
36	  var spreadsheet = SpreadsheetApp.openById(SPREADSHEET_ID);
37	  var sheet = spreadsheet.getSheetByName(SHEET_NAME);
38	
39	  if (!sheet) {
40	    sheet = spreadsheet.insertSheet(SHEET_NAME);
41	  }
42	
43	  // シートをクリアして新しいデータで上書き
44	  sheet.clear();
45	
46	  // ヘッダー行
47	  var headers = [
48	    '検索語句',
49	    'キャンペーン',
50	    '表示回数',
51	    'クリック数',
52	    'CTR(%)',
53	    '費用(円)',
54	    'CPC(円)',
55	    'コンバージョン',
56	    'コンバージョン値(円)',
57	    'CVR(%)',
58	    'CPA(円)',
59	    'エクスポート日',
60	    '期間'
61	  ];
62	  sheet.getRange(1, 1, 1, headers.length).setValues([headers]);
63	  sheet.getRange(1, 1, 1, headers.length).setFontWeight('bold');
64	
65	  // レポート期間の情報
66	  var today = new Date();
67	  var dateStr = Utilities.formatDate(today, 'Asia/Tokyo', 'yyyy-MM-dd HH:mm');
68	
69	  // Google Ads レポートクエリ（GAQL）
70	  var query =
71	    'SELECT ' +
72	    '  search_term_view.search_term, ' +
73	    '  campaign.name, ' +
74	    '  metrics.impressions, ' +
75	    '  metrics.clicks, ' +
76	    '  metrics.ctr, ' +
77	    '  metrics.cost_micros, ' +
78	    '  metrics.average_cpc, ' +
79	    '  metrics.conversions, ' +
80	    '  metrics.conversions_value, ' +
81	    '  metrics.cost_per_conversion ' +
82	    'FROM search_term_view ' +
83	    'WHERE segments.date DURING ' + DATE_RANGE + ' ' +
84	    '  AND metrics.impressions > 0 ' +
85	    'ORDER BY metrics.impressions DESC ' +
86	    'LIMIT 5000';
87	
88	  var rows = [];
89	
90	  try {
91	    var report = AdsApp.search(query);
92	
93	    while (report.hasNext()) {
94	      var row = report.next();
95	
96	      var searchTerm = row.searchTermView.searchTerm || '';
97	      var campaignName = row.campaign.name || '';
98	      var impressions = row.metrics.impressions || 0;
99	      var clicks = row.metrics.clicks || 0;
100	      var ctr = (row.metrics.ctr * 100).toFixed(2);
101	      var costMicros = row.metrics.costMicros || 0;
102	      var cost = costMicros / 1000000;  // micros → 円
103	      var avgCpc = row.metrics.averageCpc ? row.metrics.averageCpc / 1000000 : 0;
104	      var conversions = row.metrics.conversions || 0;
105	      var convValue = row.metrics.conversionsValue || 0;
106	      var cvr = clicks > 0 ? ((conversions / clicks) * 100).toFixed(2) : '0.00';
107	      var cpa = conversions > 0 ? (cost / conversions).toFixed(0) : '-';
108	
109	      rows.push([
110	        searchTerm,
111	        campaignName,
112	        impressions,
113	        clicks,
114	        ctr,
115	        Math.round(cost),
116	        Math.round(avgCpc),
117	        conversions.toFixed(1),
118	        Math.round(convValue),
119	        cvr,
120	        cpa,
121	        dateStr,
122	        DATE_RANGE
123	      ]);
124	    }
125	
126	    if (rows.length > 0) {
127	      sheet.getRange(2, 1, rows.length, headers.length).setValues(rows);
128	      Logger.log('エクスポート完了: ' + rows.length + '行の検索語句を書き込みました');
129	    } else {
130	      sheet.getRange(2, 1).setValue('データなし（期間: ' + DATE_RANGE + '）');
131	      Logger.log('検索語句データが見つかりませんでした');
132	    }
133	
134	  } catch (e) {
135	    Logger.log('エラー: ' + e.message);
136	    sheet.getRange(2, 1).setValue('エラー: ' + e.message);
137	  }
138	
139	  // 列幅自動調整
140	  for (var i = 1; i <= headers.length; i++) {
141	    sheet.autoResizeColumn(i);
142	  }
143	
144	  Logger.log('PMAX検索語句レポート自動エクスポート完了: ' + dateStr);
145	}
